function minSwaps(grid) {
    const n = grid.length;
    let steps = 0;

    for (let i = 0; i < n; ++i) {
        let row = -1;
        for (let j = i; j < n; ++j) {
            if (grid[j][i] === 0) {
                row = j;
                break;
            }
        }
