public int minSwaps(int[][] grid) {
    int n = grid.length;
    int steps = 0;

    for (int i = 0; i < n; ++i) {
        int row = -1;
        for (int j = i; j < n; ++j) {
            if (grid[j][i] == 0) {
                row = j;
                break;
            }
        }
        if (row == -1) {
            return -1;
        }

        while (row > i) {
            int[] temp = grid[row];
            grid[row] = grid[row - 1];
            grid[row - 1] = temp;
            steps++;
            row--;
        }
    }
    return steps;
}
```


